import{_ as a,o as e,c as t,ag as n}from"./chunks/framework.BZohXCq9.js";const k=JSON.parse('{"title":"第 6 章：智能分块算法","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/06-smart-chunking.md","filePath":"chapters/06-smart-chunking.md"}'),i={name:"chapters/06-smart-chunking.md"};function d(r,s,o,l,h,p){return e(),t("div",null,[...s[0]||(s[0]=[n(`<h1 id="第-6-章-智能分块算法" tabindex="-1">第 6 章：智能分块算法 <a class="header-anchor" href="#第-6-章-智能分块算法" aria-label="Permalink to &quot;第 6 章：智能分块算法&quot;">​</a></h1><blockquote><p>将一篇长文档切成大小合适、语义完整的片段，听起来简单，做起来却充满取舍——切太小丢上下文，切太大超 token 限额，切在错误的位置则会把一个完整的段落拦腰截断。qmd 的智能分块系统用一套&quot;带衰减的加权断点评分&quot;算法，优雅地解决了这个问题。</p></blockquote><h2 id="常量体系-双轨制的尺寸控制" tabindex="-1">常量体系：双轨制的尺寸控制 <a class="header-anchor" href="#常量体系-双轨制的尺寸控制" aria-label="Permalink to &quot;常量体系：双轨制的尺寸控制&quot;">​</a></h2><p>打开 <code>src/store.ts</code>，最先映入眼帘的是一组精心调校的常量（L50–59）：</p><div class="language-ts vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 文件: src/store.ts L50-59</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">CHUNK_SIZE_TOKENS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 900</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">CHUNK_OVERLAP_TOKENS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 135</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   // 15%</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">CHUNK_SIZE_CHARS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3600</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">CHUNK_OVERLAP_CHARS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 540</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">CHUNK_WINDOW_TOKENS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 200</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">CHUNK_WINDOW_CHARS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 800</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>这里存在两套平行的度量单位——token 和字符。为什么需要两套？因为 token 计数依赖分词器，调用一次分词器的开销不算小。qmd 的策略是：先用字符做快速估算（按 1 token ≈ 4 chars 的保守比例），只有在需要精确控制时才真正调用分词器。</p><p>重叠比例固定在 15%。这个数字在信息检索领域是一个经验值——太小会导致跨块查询命中率下降，太大则浪费存储和计算。<code>CHUNK_WINDOW</code> 定义了在目标切割点前后的搜索窗口，分块器会在这个窗口内寻找最佳断点，而不是粗暴地在固定位置一刀切。</p><h2 id="核心数据结构" tabindex="-1">核心数据结构 <a class="header-anchor" href="#核心数据结构" aria-label="Permalink to &quot;核心数据结构&quot;">​</a></h2><h3 id="breakpoint-接口" tabindex="-1">BreakPoint 接口 <a class="header-anchor" href="#breakpoint-接口" aria-label="Permalink to &quot;BreakPoint 接口&quot;">​</a></h3><div class="language-ts vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 文件: src/store.ts L76-80</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">interface</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> BreakPoint</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  pos</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> number</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  score</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> number</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  type</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> string</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>每个 <code>BreakPoint</code> 记录三件事：文档中的字符位置、该断点的质量评分、以及断点类型（如 <code>h2</code>、<code>blank</code> 等）。评分越高，表示在这个位置切割越&quot;干净&quot;——读者不会感到突兀。</p><h3 id="codefenceregion-接口" tabindex="-1">CodeFenceRegion 接口 <a class="header-anchor" href="#codefenceregion-接口" aria-label="Permalink to &quot;CodeFenceRegion 接口&quot;">​</a></h3><div class="language-ts vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 文件: src/store.ts L86-89</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">interface</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> CodeFenceRegion</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  start</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> number</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  end</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> number</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>代码围栏区域用于标记 \`\`\` 包裹的代码块。分块器绝不会在代码块内部切割，因为那会破坏代码的完整性，导致语法高亮失败，甚至改变语义。</p><h2 id="断点模式与优先级" tabindex="-1">断点模式与优先级 <a class="header-anchor" href="#断点模式与优先级" aria-label="Permalink to &quot;断点模式与优先级&quot;">​</a></h2><p><code>BREAK_PATTERNS</code> 数组（L97–110）是整个分块系统的&quot;知识库&quot;，它定义了 Markdown 文档中所有可能的自然断点及其优先级：</p><table tabindex="0"><thead><tr><th>模式</th><th>匹配内容</th><th>评分</th></tr></thead><tbody><tr><td>h1</td><td><code># 标题</code></td><td>100</td></tr><tr><td>h2</td><td><code>## 标题</code></td><td>90</td></tr><tr><td>h3</td><td><code>### 标题</code></td><td>80</td></tr><tr><td>codeblock</td><td><code>\`\`\`</code></td><td>80</td></tr><tr><td>h4</td><td><code>#### 标题</code></td><td>70</td></tr><tr><td>hr</td><td><code>---</code> 或 <code>***</code></td><td>60</td></tr><tr><td>h5</td><td><code>##### 标题</code></td><td>60</td></tr><tr><td>h6</td><td><code>###### 标题</code></td><td>50</td></tr><tr><td>blank</td><td>空行</td><td>20</td></tr><tr><td>list</td><td><code>- </code> 或 <code>* </code></td><td>5</td></tr><tr><td>numlist</td><td><code>1. </code></td><td>5</td></tr><tr><td>newline</td><td>换行符</td><td>1</td></tr></tbody></table><p>这个优先级设计反映了 Markdown 文档的语义层次。一级标题是最强的分界线，分数 100；代码块边界和三级标题并列为 80，因为代码块的开始/结束同样是强语义边界。空行得 20 分，是&quot;可以切但不是最佳选择&quot;的位置。列表项仅 5 分，因为列表内部通常是紧密关联的内容。换行符 1 分，是最后的退路——总比切在一个单词中间好。</p><p>值得注意的是，代码块（codeblock）的评分和 h3 一样高。这是因为代码块的起止标记本身就是天然的段落分界，在这里切割既不会破坏代码，又能保持块的语义独立性。</p><h2 id="扫描与检测" tabindex="-1">扫描与检测 <a class="header-anchor" href="#扫描与检测" aria-label="Permalink to &quot;扫描与检测&quot;">​</a></h2><h3 id="scanbreakpoints-函数" tabindex="-1">scanBreakPoints 函数 <a class="header-anchor" href="#scanbreakpoints-函数" aria-label="Permalink to &quot;scanBreakPoints 函数&quot;">​</a></h3><p><code>scanBreakPoints()</code>（L117–138）负责对整篇文档执行一次全量扫描，找出所有潜在的断点。它遍历 <code>BREAK_PATTERNS</code> 中的每个正则表达式，对文档执行全局匹配。当同一个位置被多个模式命中时（例如一个空行恰好在标题前面），只保留评分最高的那个。最终结果按位置排序返回。</p><p>这个&quot;一次扫描、全局复用&quot;的设计很重要。在后续的分块循环中，每次寻找切割点时不需要重新扫描文档，只需在预计算的断点数组中做区间查询即可。</p><h3 id="findcodefences-函数" tabindex="-1">findCodeFences 函数 <a class="header-anchor" href="#findcodefences-函数" aria-label="Permalink to &quot;findCodeFences 函数&quot;">​</a></h3><p><code>findCodeFences()</code>（L144–166）追踪文档中所有代码围栏的开闭状态。它从头到尾扫描 \`\`\` 标记，遇到开标记记录起点，遇到闭标记记录终点。如果文档末尾有未闭合的围栏，该区域会自动延伸到文档结尾——这是一种防御性设计，避免因格式错误导致分块器在代码内部切割。</p><h3 id="isinsidecodefence-函数" tabindex="-1">isInsideCodeFence 函数 <a class="header-anchor" href="#isinsidecodefence-函数" aria-label="Permalink to &quot;isInsideCodeFence 函数&quot;">​</a></h3><p><code>isInsideCodeFence()</code>（L171–173）是一个简洁的辅助函数，判断给定位置是否落在任何代码围栏区域内。如果是，该位置就不能作为切割点，无论它的断点评分有多高。</p><h2 id="核心算法-findbestcutoff" tabindex="-1">核心算法：findBestCutoff <a class="header-anchor" href="#核心算法-findbestcutoff" aria-label="Permalink to &quot;核心算法：findBestCutoff&quot;">​</a></h2><p><code>findBestCutoff()</code>（L188–224）是整个分块系统最精妙的部分。它的任务是：在目标切割位置附近的窗口内，找到一个&quot;综合最优&quot;的断点。</p><h3 id="平方距离衰减" tabindex="-1">平方距离衰减 <a class="header-anchor" href="#平方距离衰减" aria-label="Permalink to &quot;平方距离衰减&quot;">​</a></h3><p>算法的核心思想是：断点离目标位置越远，它的有效评分越低。但这个衰减不是线性的，而是平方的：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>normalizedDist = distance / windowSize    // 归一化到 [0, 1]</span></span>
<span class="line"><span>multiplier = 1.0 - (normalizedDist ^ 2) * decayFactor</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>其中 <code>decayFactor = 0.7</code>。这意味着在窗口内不同位置的乘数如下：</p><table tabindex="0"><thead><tr><th>距目标的位置</th><th>归一化距离</th><th>乘数</th></tr></thead><tbody><tr><td>目标位置</td><td>0%</td><td>1.000</td></tr><tr><td>窗口 25% 处</td><td>0.25</td><td>0.956</td></tr><tr><td>窗口 50% 处</td><td>0.50</td><td>0.825</td></tr><tr><td>窗口 75% 处</td><td>0.75</td><td>0.606</td></tr><tr><td>窗口边缘</td><td>1.00</td><td>0.300</td></tr></tbody></table><p>最终评分 = 断点基础分 × 乘数。</p><h3 id="为什么用平方而不是线性" tabindex="-1">为什么用平方而不是线性？ <a class="header-anchor" href="#为什么用平方而不是线性" aria-label="Permalink to &quot;为什么用平方而不是线性？&quot;">​</a></h3><p>线性衰减（<code>1 - dist * decay</code>）的问题是衰减速度恒定。一个 h2 标题（90 分）在窗口 50% 处会被线性衰减削弱到 <code>90 × 0.65 = 58.5</code>，这可能低于目标位置附近的空行（<code>20 × 1.0 = 20</code>）。但事实上，在 h2 标题处切割几乎总是更好的选择。</p><p>平方衰减则更温和——在窗口前半段衰减很慢，后半段才急剧下降。同样的 h2 在 50% 处得分是 <code>90 × 0.825 = 74.25</code>，远高于任何低质量断点。这确保了高质量的语义断点即使距离较远，仍然能击败目标位置附近的低质量断点。</p><p>代码中还会跳过落在代码围栏内的断点，确保不会在代码块中间切割。</p><h2 id="字符级分块器-chunkdocument" tabindex="-1">字符级分块器：chunkDocument <a class="header-anchor" href="#字符级分块器-chunkdocument" aria-label="Permalink to &quot;字符级分块器：chunkDocument&quot;">​</a></h2><p><code>chunkDocument()</code>（L2024–2085）是面向字符的主分块函数。它的工作流程如下：</p><p>首先，预扫描整篇文档，生成断点列表和代码围栏区域列表。这两个数据结构在整个分块过程中复用，避免重复计算。</p><p>然后进入主循环：从当前位置出发，向前推进 <code>CHUNK_SIZE_CHARS</code> 个字符作为目标切割点，调用 <code>findBestCutoff()</code> 在窗口内寻找最佳断点。找到后，从当前位置到断点位置的文本成为一个块。下一个块的起点则回退 <code>CHUNK_OVERLAP_CHARS</code> 个字符，形成重叠区域。</p><p>重叠区域的存在保证了跨块边界的内容不会&quot;消失&quot;。如果用户搜索的关键词恰好跨越两个块的边界，至少有一个块能完整包含它。</p><h2 id="token-级分块器-chunkdocumentbytokens" tabindex="-1">Token 级分块器：chunkDocumentByTokens <a class="header-anchor" href="#token-级分块器-chunkdocumentbytokens" aria-label="Permalink to &quot;Token 级分块器：chunkDocumentByTokens&quot;">​</a></h2><p><code>chunkDocumentByTokens()</code>（L2091–2137）在字符级分块器的基础上增加了 token 精度控制。它采用两阶段策略：</p><p>第一阶段：用保守的字符估算（3 chars/token，比通常的 4 更保守）调用字符级分块器，得到初步的分块结果。</p><p>第二阶段：对每个块调用真正的 LLM 分词器计算 token 数。如果某个块仍然超过 <code>CHUNK_SIZE_TOKENS</code>，则对该块单独再次分割。</p><p>这种两阶段方法在精度和性能之间取得了平衡。大多数块在第一阶段就满足 token 限制，只有少数边界情况需要第二阶段的修正。保守的 3 chars/token 估算确保第一阶段宁可切得小一点，也不要产生太多超限的块。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><p>qmd 的智能分块系统是一个精心设计的多层架构。常量体系提供了字符和 token 的双轨控制；<code>BREAK_PATTERNS</code> 编码了 Markdown 的语义层次知识；<code>scanBreakPoints()</code> 和 <code>findCodeFences()</code> 通过一次性预扫描避免重复计算；<code>findBestCutoff()</code> 用平方距离衰减在&quot;切割质量&quot;和&quot;位置偏好&quot;之间找到最优平衡；两级分块器则在性能和精度之间取得了务实的折中。整套设计的核心洞察是：分块不是一个纯数学问题，而是一个需要理解文档语义结构的信息检索问题。</p>`,51)])])}const u=a(i,[["render",d]]);export{k as __pageData,u as default};
